+            floor_z: 120.0,
+            ceil_z: 420.0,
+            light: 200.0,
+        });
+        let mut p = Player {
+            on_ground: false,
+            pos: [0.0, 0.0, 10.0],
+            vel: [0.0, 0.0, 0.0],
